INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Primero Básico', 'Comunicación y Lenguaje L1', 'Competencia 1: Se comunica en forma oral, atendiendo a las intenciones, la situación comunicativa, sus recursos expresivos, entre otros.', ARRAY['1.1 Infiere el significado del mensaje tomando en cuenta el contexto, las intenciones del emisor y sus propios propósitos de escucha.', '1.2. Controla la eficacia de la propia comunicación y la modifica al saber repetir, ampliar, parafrasear el mensaje o utilizar otro tipo de registro lingüístico.', '1.3. Muestra empatía hacia su interlocutor y su mensaje, con relación al sentido, finalidades del discurso, punto de vista.']),
('Primero Básico', 'Comunicación y Lenguaje L1', 'Competencia 2: Desarrolla habilidades de entendimiento, comprensión e interpretación de lo que lee.', ARRAY['2.1. Regula su fluidez lectora, según el tipo de texto.', '2.2. Desarrolla habilidades de comprensión.', '2.3. Lee con placer obras literarias, especialmente de autores guatemaltecos.']),
('Primero Básico', 'Comunicación y Lenguaje L1', 'Competencia 3: Redacta textos en forma autónoma, según las distintas intenciones y situaciones comunicativas.', ARRAY['3.1. Escribe textos claros y precisos, teniendo en cuenta las fases de la redacción.', '3.2. Redacta textos apegados a la gramática del idioma.', '3.3 Valora la precisión y corrección en lo que escribe y publica.']);
